es": human_bytes} ''') write("library/system_report.py", ''' #!/usr/bin/python from ansible.module_utils.basic import AnsibleModule import platform, os def main(): module = AnsibleModule( argument_spec=dict( label=dict(type="str", required=True), threshold=dict(type="int", required=False, default=80), ), supports_check_mode=True, ) report = { "label": module.params["label"], "system": platform.system(), "release": platform.release(), "python": platform.python_version(), "cpu_count": os.cpu_count(), "threshold": module.params["threshold"], } module.exit_json(changed=False, report=report, message="Report generated for %s" % module.params["label"]) if __name__ == "__main__": main() ''') We define shared group variables and host-specific variables to show how Ansible manages configuration data and applies variable precedence. We then create a custom Jinja2 filter plugin that converts text into slugs and formats byte values into readable units. We also built a custom Python-based Ansible module that generates a simple system report for each host. Copy Code Copied Use a different Browser write("roles/webserver/defaults/main.yml", """ --- listen_port: 8080 """) write("roles/webserver/vars/main.yml", """ --- doc_root: "/tmp/www" """) write("roles/webserver/tasks/main.yml", """ --- - name: Ensure docroot exists ansible.builtin.file: path: "{{ doc_root }}" state: directory mode: "0755" - name: Deploy index.html from a Jinja2 template ansible.builtin.template: src: index.html.j2 dest: "{{ doc_root }}/index.html" notify: Restart web service - name: Run handlers immediately (instead of end of play) ansible.builtin.meta: flush_handlers """) write("roles/webserver/handlers/main.yml", """ --- - name: Restart web service ansible.builtin.debug: msg: "(simulated) restarting web service on port {{ listen_port }}" """) write("roles/webserver/templates/index.html.j2", """ &lt;!DOCTYPE html> &lt;html> &lt;head>&lt;title>{{ app_name }}&lt;/title>&lt;/head> &lt;body> &lt;h1>{{ app_name }} v{{ app_version }}&lt;/h1> &lt;p>Served on port {{ listen_port }} from {{ doc_root }}&lt;/p> &lt;p>Host: {{ inventory_hostname }}&lt;/p> &lt;/body> &lt;/html> """) write("templates/report.txt.j2", """ Deployment Report ================= App: {{ app_name }} ({{ app_version }}) Host: {{ inventory_hostname }} Generated: {{ ansible_date_time.iso8601 | default('n/a') }} Slug: {{ app_name | to_slug }} Packages: {% for p in packages %} - {{ p }} {% endfor %} Cache enabled: {{ feature_flags.enable_cache }} Metrics enabled: {{ feature_flags.enable_metrics }} """) dyn = write("dynamic_inventory.py", ''' #!/usr/bin/env python3 import json, sys INV = { "webservers": {"hosts": ["web1", "web2"], "vars": {"role": "frontend"}}, "dbservers": {"hosts": ["db1"], "vars": {"role": "backend"}}, "_meta": { "hostvars": { "web1": {"ansible_connection": "local", "tier": "gold"}, "web2": {"ansible_connection": "local", "tier": "silver"}, "db1": {"ansible_connection": "local", "tier": "gold"}, } }, } if "--host" in sys.argv: print(json.dumps({})) else: print(json.dumps(INV, indent=2)) ''') os.chmod(dyn, os.stat(dyn).st_mode | stat.S_IEXEC | stat.S_IXGRP | stat.S_IXOTH) We create a complete web server role with defaults, variables, tasks, handlers, and te

